	TweenTime = 0.5,

	HoverScale = 1.1,
	HoverTweenTime = 0.15,
	ButtonPattern = "^Buy%d+$",

	RainbowStep = 0.01,
	RainbowInterval = 0.03,

	BlurSize = 10,
	FOVScale = 0.9,
