local function trim(str)
	if not str then return "" end
	return (string.gsub(str, "^%s*(.-)%s*$", "%1"))
end

local function GetAvatar(userId)
	if not userId or typeof(userId) ~= "number" then 
		return "rbxassetid://0" 
	end
	local success, url = pcall(Players.GetUserThumbnailAsync, Players, userId, Enum.ThumbnailType.HeadShot, Enum.ThumbnailSize.Size420x420)
	return success and url or "rbxassetid://0"
end


