local function SetupButtonHover(btnFrame, originalColor)
	local btn = btnFrame:FindFirstChildWhichIsA("TextButton") or btnFrame
	btn.Active = true
	local tweenInfo = TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	local hoverColor = Color3.new(
		originalColor.R * HOVER_DARKEN,
		originalColor.G * HOVER_DARKEN,
		originalColor.B * HOVER_DARKEN
	)

	btnFrame.MouseEnter:Connect(function()
		if btnFrame.BackgroundColor3 ~= COLOR_ACTIVE then
			TweenService:Create(btnFrame, tweenInfo, { BackgroundColor3 = hoverColor }):Play()
		end
	end)
	btnFrame.MouseLeave:Connect(function()
		if btnFrame.BackgroundColor3 ~= COLOR_ACTIVE then
			TweenService:Create(btnFrame, tweenInfo, { BackgroundColor3 = originalColor }):Play()
		end
	end)
end

