local RunService = game:GetService("RunService")

local function MakeResponsive(screenGui: ScreenGui, referenceSize: Vector2?)
	referenceSize = referenceSize or Vector2.new(1920, 1080)

	if not screenGui:IsA("ScreenGui") then
		error("MakeResponsive: нужен ScreenGui")
	end

	screenGui.IgnoreGuiInset = true

	local uiScale = screenGui:FindFirstChild("_AutoScale")
	if not uiScale then
		uiScale = Instance.new("UIScale")
		uiScale.Name = "_AutoScale"
		uiScale.Parent = screenGui
	end

	local function updateScale()
		local camera = workspace.CurrentCamera
		if not camera then return end

		local viewport = camera.ViewportSize
		if viewport.X <= 0 or viewport.Y <= 0 then return end

		local scaleX = viewport.X / referenceSize.X
		local scaleY = viewport.Y / referenceSize.Y

		uiScale.Scale = math.min(scaleX, scaleY)
	end


	local function bindCamera()
		local camera = workspace.CurrentCamera
		if not camera then return end

		camera:GetPropertyChangedSignal("ViewportSize"):Connect(updateScale)
	end

	if workspace.CurrentCamera then
		bindCamera()
	else
		workspace:GetPropertyChangedSignal("CurrentCamera"):Wait()
		bindCamera()
	end

	workspace:GetPropertyChangedSignal("CurrentCamera"):Connect(bindCamera)

	RunService.RenderStepped:Connect(updateScale)

	updateScale()
end

MakeResponsive(root, Vector2.new(1920, 1080))